import{_ as o,o as r,c as a,ai as e}from"./chunks/framework.DMjte4z8.js";const g=JSON.parse('{"title":"任务系统入门：制作有剧情的任务","description":"","frontmatter":{"title":"任务系统入门：制作有剧情的任务","category":"rpg-systems","updated":"2026-04-28T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://www.youtube.com/watch?v=Y_JTapzL9Bs","https://www.thehelper.net/threads/quest-types-and-how-to-make-them.32197/","https://www.youtube.com/watch?v=6Eg3qLISI_E","https://blog.csdn.net/gitblog_00916/article/details/160329952","https://www.youtube.com/watch?v=hvtG7-BHv9s"]},"headers":[],"relativePath":"rpg-systems/任务系统入门制作有剧情的任务.md","filePath":"rpg-systems/任务系统入门制作有剧情的任务.md","lastUpdated":1777383225000}'),l={name:"rpg-systems/任务系统入门制作有剧情的任务.md"};function s(n,t,u,i,q,p){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="任务系统入门-制作有剧情的任务" tabindex="-1">任务系统入门：制作有剧情的任务 <a class="header-anchor" href="#任务系统入门-制作有剧情的任务" aria-label="Permalink to “任务系统入门：制作有剧情的任务”">​</a></h1><h2 id="任务系统基础概念" tabindex="-1">任务系统基础概念 <a class="header-anchor" href="#任务系统基础概念" aria-label="Permalink to “任务系统基础概念”">​</a></h2><p>本节将带你认识什么是任务系统，以及为什么在你的RPG地图中需要它。学完本节后，你将理解任务系统的核心概念，为后续创建第一个任务打下基础[^1][^3]。</p><h3 id="什么是任务系统" tabindex="-1">什么是任务系统 <a class="header-anchor" href="#什么是任务系统" aria-label="Permalink to “什么是任务系统”">​</a></h3><p>任务系统是 Warcraft 3 地图编辑器中的一种机制，它允许你在游戏中创建<strong>任务目标</strong>，并引导玩家逐步完成这些目标[^2]。你可以把它想象成游戏给玩家的&quot;待办清单&quot;——告诉玩家需要做什么事情。</p><p>在编辑器中，任务系统是通过<strong>触发器（Trigger）</strong> 来实现的。触发器就像游戏里的&quot;自动化脚本&quot;，当满足某些条件时，它会自动执行预设好的动作[^4]。比如，当玩家与某个NPC对话后，触发器可以自动添加一个新任务到玩家的任务列表中。</p><h3 id="任务系统在rpg地图中的作用" tabindex="-1">任务系统在RPG地图中的作用 <a class="header-anchor" href="#任务系统在rpg地图中的作用" aria-label="Permalink to “任务系统在RPG地图中的作用”">​</a></h3><p>任务系统在RPG地图中有三大核心作用：</p><p><strong>第一，提供游戏目标</strong>。没有任务的RPG地图就像一本没有章节的书，玩家可能不知道该做什么。有了任务，玩家就有了明确的方向[^2]。</p><p><strong>第二，讲述游戏故事</strong>。通过任务的顺序和内容，你可以向玩家展示剧情的发展，让玩家在完成任务的过程中体验你设计的故事情节[^4][^5]。</p><p><strong>第三，引导玩家探索</strong>。你可以设计任务来指引玩家前往不同的区域，接触不同的内容，这样就不会让玩家在地图中迷失方向。</p><h3 id="为什么rpg地图需要剧情任务" tabindex="-1">为什么RPG地图需要剧情任务 <a class="header-anchor" href="#为什么rpg地图需要剧情任务" aria-label="Permalink to “为什么RPG地图需要剧情任务”">​</a></h3><p>如果你只是想让玩家打怪升级，没有剧情任务也可以。但是，如果你想让玩家真正沉浸在你的地图中，体验你精心设计的故事和世界观，那么剧情任务就是必不可少的[^5]。</p><p>一个好的剧情任务系统可以：</p><ul><li>让玩家对你的地图留下深刻印象</li><li>增加玩家的游戏时长和重复游玩价值</li><li>展现你作为地图创作者的创意和用心</li></ul><blockquote><p><strong>💡 新手提示</strong>：任务系统虽然看起来复杂，但它的核心逻辑其实很简单——就是&quot;当玩家做了什么事，就给他一个任务；当他完成了任务要求，就奖励他&quot;。记住这个基本思路，后面的操作就会变得清晰。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手一上来就想做复杂的支线任务系统，结果被搞晕了。建议先从最简单的&quot;一个任务+一个目标&quot;开始，等熟练后再逐步增加复杂度。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>现在你应该理解了：</p><ul><li>任务系统是引导玩家完成游戏目标的机制</li><li>它通过触发器来实现自动化控制</li><li>剧情任务能提升RPG地图的沉浸感和游戏体验</li></ul><p>准备好之后，让我们进入下一节，开始创建你的第一个任务！</p><h2 id="world-editor任务触发器入门" tabindex="-1">World Editor任务触发器入门 <a class="header-anchor" href="#world-editor任务触发器入门" aria-label="Permalink to “World Editor任务触发器入门”">​</a></h2><p>本节将带你认识触发编辑器的基本界面，学习创建任务所需的核心功能，并亲手制作你的第一个任务触发器。学完后，你将能够制作一个完整的、可交互的任务系统。</p><h3 id="认识触发编辑器界面" tabindex="-1">认识触发编辑器界面 <a class="header-anchor" href="#认识触发编辑器界面" aria-label="Permalink to “认识触发编辑器界面”">​</a></h3><ol><li><strong>打开触发编辑器</strong> — 在World Editor顶部菜单栏点击&quot;触发编辑器&quot;按钮（或者直接按键盘上的 <strong>F4</strong> 键）[^1]</li><li><strong>查看左侧触发器列表</strong> — 这里是管理所有触发器的地方，类似于文件夹，可以新建文件夹来分类整理你的触发器</li><li><strong>查看右侧编辑器区域</strong> — 当你点击某个触发器时，右侧会显示该触发器的详细内容，包括&quot;事件&quot;、&quot;条件&quot;、&quot;动作&quot;三个部分[^3]</li><li><strong>理解&quot;事件-条件-动作&quot;结构</strong> — 这是触发器的核心逻辑： <ul><li><strong>事件</strong>：满足什么条件时触发（比如&quot;单位死亡&quot;）</li><li><strong>条件</strong>：额外需要满足什么（比如&quot;死亡的单位是指定的怪物&quot;）</li><li><strong>动作</strong>：触发后执行什么操作（比如&quot;显示任务完成&quot;）[^2]</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：触发编辑器的界面元素较多，初次打开可能会觉得复杂。建议先把左侧的触发器列表和右侧的编辑区域看清楚，不要急着修改任何设置。</p></blockquote><h3 id="任务相关的常用事件和动作" tabindex="-1">任务相关的常用事件和动作 <a class="header-anchor" href="#任务相关的常用事件和动作" aria-label="Permalink to “任务相关的常用事件和动作”">​</a></h3><ol><li><strong>打开触发编辑器</strong> — 按F4进入触发编辑器界面</li><li><strong>新建一个触发器</strong> — 在左侧空白处右键，选择&quot;新建触发器&quot;，并给它起名（比如&quot;主线任务-第一章&quot;）</li><li><strong>添加触发事件</strong> — 点击触发器的&quot;事件&quot;区域，选择&quot;单位&quot;类别下的&quot;单位死亡事件&quot;[^1]</li><li><strong>添加任务创建动作</strong> — 在&quot;动作&quot;区域添加&quot;任务-创建任务&quot;动作，设置任务的标题和描述</li><li><strong>添加任务完成动作</strong> — 同样在&quot;动作&quot;区域添加&quot;任务-标记任务完成&quot;动作[^2]</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记给触发器起名字，导致后续查找和修改时非常困难。建议在创建触发器的第一时间就命名，并且命名要清晰明了。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你已经了解了触发编辑器的基本界面结构，认识了&quot;事件-条件-动作&quot;的核心逻辑，并学会了如何创建任务相关的触发器。现在你可以尝试制作一个简单的任务：让玩家与某个NPC对话后，接取一个&quot;消灭10只狼&quot;的任务，当任务完成后显示奖励提示。建议先从单一任务开始练习，熟练后再逐步增加任务的复杂程度。</p><h2 id="创建基础任务流程" tabindex="-1">创建基础任务流程 <a class="header-anchor" href="#创建基础任务流程" aria-label="Permalink to “创建基础任务流程”">​</a></h2><p>本节我们将学习在 Warcraft III 世界编辑器中创建最基本的任务流程。完成学习后，你将能够制作一个简单的任务——玩家与NPC对话后接受任务，然后完成特定目标即可获得奖励。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：创建任务变量</strong> — 在触发器编辑器的左侧面板，找到&quot;变量&quot;选项并点击新建（绿色加号按钮）[^1]。变量就像是一个&quot;容器&quot;，用来存储你的任务信息。为变量起一个易懂的名字，比如&quot;任务_01&quot;，类型选择&quot;任务&quot;[^2]。</p></li><li><p><strong>第二步：新建任务触发器</strong> — 在触发器编辑器中点击&quot;新建触发器&quot;按钮（黄色闪电图标）。双击触发器名称可以重命名为&quot;任务_接受&quot;。接下来，我们需要添加&quot;任务-创建任务&quot;动作，在弹出的设置窗口中填写任务的标题和描述文字[^3]。</p></li><li><p><strong>第三步：设置任务目标与完成条件</strong> — 继续在触发器中添加&quot;任务-创建任务目标&quot;动作。每个任务可以包含多个小目标，比如&quot;杀死5只狼&quot;或&quot;收集10个木材&quot;。这里要明确告诉系统：玩家做到了什么，就算目标完成了[^2]。</p></li><li><p><strong>第四步：设置触发条件（任务何时被激活）</strong> — 回到触发器的事件面板，点击绿色加号添加触发事件。对于接受任务的场景，通常选择&quot;单位 - A unit 发起对话&quot;事件[^1]。然后在条件面板设置：只有特定单位（比如NPC）被对话时，才触发此任务。</p></li><li><p><strong>第五步：完成任务的判定逻辑</strong> — 创建另一个触发器专门判断任务何时完成。比如当玩家杀死了足够数量的怪物时，添加&quot;任务-完成任务目标&quot;的动作；当所有目标都达成后，添加&quot;任务-完成任务&quot;动作，同时别忘了给玩家发放奖励[^1][^2]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：在设置任务变量时，养成好习惯用中文命名。虽然系统支持英文，但使用&quot;任务_第一章_狼皮收集&quot;这样的命名方式，在你回头修改地图时会轻松很多。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手只创建了&quot;接受任务&quot;的触发器，却忘记了创建&quot;完成任务&quot;的触发器。结果玩家点了NPC后，任务显示已完成但没有反应——这是因为缺少判定完成的逻辑。解决方法是在接受任务触发器后，立即创建一个独立的&quot;完成任务判定&quot;触发器。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上五个步骤后，你的第一个任务就基本成型了。测试时，按下F6打开触发器调试模式，可以看到任务是否正确显示在屏幕右上角。玩家与NPC对话后，任务目标会出现；完成目标后，任务会自动标记为完成并发放奖励。如果有任何问题，逐个检查每个触发器的事件、条件、动作是否正确连接。</p><h2 id="为任务添加剧情对话" tabindex="-1">为任务添加剧情对话 <a class="header-anchor" href="#为任务添加剧情对话" aria-label="Permalink to “为任务添加剧情对话”">​</a></h2><p>在本节中，你将学习如何在任务中添加生动的剧情对话，让NPC能够与玩家进行互动交流。学完本节后，你的任务将不再是冷冰冰的&quot;完成击杀&quot;，而是会有一段段精彩的故事等待玩家体验。</p><h3 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：打开触发器编辑器</strong> — 在World Editor顶部菜单栏点击&quot;触发器&quot;按钮（扳手图标）[^1]进入触发器编辑器。这是整个任务系统的&quot;大脑&quot;，所有对话和剧情逻辑都在这里编写。</p></li><li><p><strong>第二步：创建对话事件</strong> — 右键点击左侧触发器列表，选择&quot;新建触发器&quot;，然后为其命名（如&quot;森林对话&quot;）。点击&quot;事件&quot;区域添加触发条件，例如&quot;单位进入区域&quot;[^4]，这样当玩家靠近NPC时，对话就会自动触发。</p></li><li><p><strong>第三步：添加对话显示动作</strong> — 在触发器的&quot;动作&quot;区域，点击加号添加动作。选择&quot;对话-显示对玩家说话文本&quot;[^2]，在弹出的窗口中填写NPC要说的话。例如：&quot;旅行者，你好！我的村庄正遭受野兽的袭击。&quot;</p></li><li><p><strong>第四步：编写任务描述</strong> — 创建新触发器专门管理任务文本。选择&quot;任务-创建任务&quot;动作，填写任务标题和详细描述。描述中要清楚说明&quot;做什么&quot;和&quot;为什么做&quot;[^2]，比如：&quot;帮助村长击退狼群——村长说狼穴在村庄北方的森林中。&quot;</p></li><li><p><strong>第五步：实现选择分支</strong> — 如果希望对话有多个选项，需要添加&quot;对话框-显示选择&quot;动作[^4]。为每个选项设置不同的后果——比如&quot;帮助村民&quot;会触发任务，而&quot;拒绝请求&quot;则播放另一段对话。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：对话文本中的&quot;|cFFFFCC00&quot;这样的代码是颜色代码，可以改变文字颜色。&quot;|r&quot;代表重置为默认颜色。你可以适当使用颜色来突出重要信息，但不要过度使用，否则会让玩家眼花缭乱。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手只创建了对话，却没有设置触发条件，导致对话永远不出现。一定要检查&quot;事件&quot;区域是否为空——如果为空，点击添加&quot;地图初始化&quot;或&quot;单位进入区域&quot;等事件来启动触发器[^3]。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，当你运行地图并让玩家靠近NPC时，应该能看到NPC头顶飘出对话气泡，屏幕中央也会显示详细的对话文字。如果创建了任务目标，玩家会在任务面板中看到新的任务条目。选择分支功能则为你的剧情增添了深度，让玩家能够影响故事的发展方向。</p><h2 id="任务追踪与奖励系统" tabindex="-1">任务追踪与奖励系统 <a class="header-anchor" href="#任务追踪与奖励系统" aria-label="Permalink to “任务追踪与奖励系统”">​</a></h2><p>在本节中，你将学习如何让玩家看到任务进度，以及如何给完成任务的角色发放奖励。学完本节后，你的任务系统将变得完整——玩家不仅能看到自己接了什么任务，还能获得相应的回报！</p><h3 id="操作步骤-2" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-2" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：启用任务日志显示</strong> — 打开触发器编辑器（点击编辑器上方的&quot;触发器&quot;按钮），创建一个新触发器。选择&quot;游戏&quot;类别下的&quot;显示任务日志&quot;动作[^1][^3]。这样玩家在游戏中打开界面（按L键）时，就能看到任务面板，其中会列出当前所有进行中的任务。</p></li><li><p><strong>第二步：添加任务奖励</strong> — 在玩家完成任务的触发器中，找到&quot;游戏&quot;类别，添加&quot;给予黄金&quot;、&quot;给予经验值&quot;等动作来发放奖励[^2]。你需要指定奖励的具体数值，这些数值可以是固定的数字，也可以设置为变量，让奖励根据任务难度自动调整。</p></li><li><p><strong>第三步：管理多阶段任务状态</strong> — 使用&quot;任务&quot;类别下的&quot;创建任务&quot;动作来初始化一个新任务，设置任务标题和描述[^4]。当玩家完成某个阶段目标时，用&quot;更新任务描述&quot;动作来修改任务显示的文字，告知玩家进度更新。当所有条件满足后，使用&quot;完成任务&quot;动作标记任务完成，此时任务会从&quot;进行中&quot;移至&quot;已完成&quot;列表。</p></li><li><p><strong>第四步：实现多任务追踪</strong> — 如果需要同时管理多个任务，可以创建多个任务对象并分别赋值给不同的变量[^2]。这样你可以精确控制每个任务的显示状态、解锁条件和奖励发放，实现复杂的任务链设计。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：奖励不一定非要是黄金和经验值！你还可以通过&quot;给予物品&quot;动作奖励装备道具，或者用触发器解锁新的游戏区域，让奖励更有吸引力。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手忘记给奖励触发器设置正确的执行条件，导致奖励在任何情况下都会发放。务必在触发器中用&quot;条件&quot;或&quot;如果/那么/否则&quot;动作来限制奖励的发放时机。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的任务系统将具备完整的追踪和奖励功能。玩家可以通过任务日志清晰看到当前任务的进度，完成任务后会自动获得你设定的奖励，任务状态也会相应更新显示。</p><h2 id="调试技巧与学习资源" tabindex="-1">调试技巧与学习资源 <a class="header-anchor" href="#调试技巧与学习资源" aria-label="Permalink to “调试技巧与学习资源”">​</a></h2><p>本节将教你如何排查任务触发器中的问题，并推荐一些优质的学习资料。学完本节后，你将能够独立诊断并修复常见的任务系统错误。</p><h3 id="触发器调试的基本方法" tabindex="-1">触发器调试的基本方法 <a class="header-anchor" href="#触发器调试的基本方法" aria-label="Permalink to “触发器调试的基本方法”">​</a></h3><p>调试（Debug）就是找出触发器哪里出了问题并修复的过程。当你发现任务不工作时，可以用以下方法逐步排查。</p><p><strong>第一步：使用“显示文本消息”测试触发器是否运行</strong> — 在触发器开头添加一个“显示文本消息”动作（Set Text to &quot;触发器已执行&quot;）[^1]，这样当你进入游戏测试时，屏幕上方会显示文字，告诉你这个触发器有没有被激活。</p><p><strong>第二步：检查触发器的执行条件</strong> — 确认“条件”栏里的条件是否都满足了。比如检查触发单位是否正确、变量值是否符合预期等。如果条件不满足，触发器根本不会运行。</p><p><strong>第三步：逐步注释掉部分动作来定位问题</strong> — 把触发器里的动作一条条注释掉（右键动作选择“禁用”），然后重新测试。哪条注释掉后问题消失了，问题就出在哪条动作上[^2]。</p><p><strong>第四步：使用“游戏日志”查看错误信息</strong> — 在触发器里加入“为聊天信息创建任务”动作，然后打开游戏的日志文件查看是否有报错提示。</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手以为触发器写错了才会出问题，其实更常见的是触发器根本没被执行。如果你的任务没有任何反应，首先用显示文本消息确认触发器是否真的在运行。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：测试时尽量一个人测试，多人联机时触发器行为可能不一致，会干扰你的判断。</p></blockquote><h3 id="新手常犯的错误与避免方法" tabindex="-1">新手常犯的错误与避免方法 <a class="header-anchor" href="#新手常犯的错误与避免方法" aria-label="Permalink to “新手常犯的错误与避免方法”">​</a></h3><p><strong>错误一：忘记给任务目标设置完成条件</strong> — 很多新手创建了任务，但玩家完成后任务却无法结束。这是因为你没有添加“任务条件”触发的逻辑[^2]。解决方法是：在任务触发器旁边，再创建一个新的“任务条件”触发器，当玩家达成条件时自动触发任务完成。</p><p><strong>错误二：变量类型不匹配</strong> — 比如你定义了一个整数变量，但误把它当成实数（有小数点的数字）使用。编辑器会报类型错误，触发器直接失效。解决方法：创建变量时仔细选择类型，创建后可以在变量列表里右键查看类型。</p><p><strong>错误三：单位被提前删除</strong> — 有些触发器需要引用某个单位，但你可能在另一个触发器里提前把它删了。检查你的“单位 - 移除”动作，确保不会误删正在使用的单位[^4]。</p><p><strong>错误四：忽略触发器的开启/关闭状态</strong> — 每个触发器左上角都有一个复选框控制是否启用。如果不小心取消了勾选，整个触发器就不会工作。养成定期检查的习惯。</p><blockquote><p><strong>💡 新手提示</strong>：养成“每写一个功能就立刻测试一次”的习惯，不要等写完了几十个触发器再一起测试，到时候很难定位问题出在哪里。</p></blockquote><h3 id="推荐的学习资料与社区" tabindex="-1">推荐的学习资料与社区 <a class="header-anchor" href="#推荐的学习资料与社区" aria-label="Permalink to “推荐的学习资料与社区”">​</a></h3><p><strong>视频教程</strong> — B站和YouTube上有大量 Warcraft 3 World Editor 基础教程[^1][^3]，推荐从“任务系统入门”关键词搜索，观看手把手演示。</p><p><strong>The Helper 论坛</strong> — 这是全球最大的魔兽争霸地图制作社区，里面有详细的图文教程，包括任务类型的创建方法[^2]。</p><p><strong>HiveWE 编辑器指南</strong> — HiveWE 是一款改进版的地图编辑器，它的指南文档详细介绍了剧情触发器、对话系统和任务推进机制[^4]。</p><p><strong>战役编辑器教程</strong> — 如果你想制作类似官方战役的剧情体验，可以学习战役编辑器的使用方法[^5]。</p><blockquote><p><strong>💡 新手提示</strong>：学习资源在精不在多。建议先完整跟着一个教程做一遍，不要同时看太多教程导致信息混乱。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该能够：</p><ul><li>使用“显示文本消息”验证触发器是否正常执行</li><li>通过逐条注释法定位触发器中的具体问题</li><li>识别并避免新手最常见的四种错误</li><li>知道从哪里获取高质量的学习资料</li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.youtube.com/watch?v=Y_JTapzL9Bs" target="_blank" rel="noreferrer">Warcraft 3 World Editor Tutorial - Quest Examples</a> — accessed 2026-04-28 [^2]: <a href="https://www.thehelper.net/threads/quest-types-and-how-to-make-them.32197/" target="_blank" rel="noreferrer">Tutorial - Quest Types and How to Make them - Headline News</a> — accessed 2026-04-28 [^3]: <a href="https://www.youtube.com/watch?v=6Eg3qLISI_E" target="_blank" rel="noreferrer">Warcraft 3 World Editor Tutorial - Quests</a> — accessed 2026-04-28 [^4]: <a href="https://blog.csdn.net/gitblog_00916/article/details/160329952" target="_blank" rel="noreferrer">革命性魔兽争霸III地图编辑器：HiveWE全面使用指南</a> — accessed 2026-04-28 [^5]: <a href="https://www.youtube.com/watch?v=hvtG7-BHv9s" target="_blank" rel="noreferrer">Warcraft 3 World Editor Tutorial: Campaign Editor Part 1</a> — accessed 2026-04-28</p>',82)])])}const d=o(l,[["render",s]]);export{g as __pageData,d as default};
